import random, itertools, math
def hug_F(bs,p,h=1.0,delta=0.0):
    q=1-p; B=sum(bs); T=p*(B+h)+delta
    U=L=0.0
    n=len(bs)
    for mask in range(1<<n):
        s=0; k=0
        for i,b in enumerate(bs):
            if mask>>i & 1:
                s+=b; k+=1
        prob=p**k*q**(n-k)
        if s >= T-1e-12:
            U+=prob
        if s < T-h-1e-12:
            L+=prob
    return q*U-p*L, U,L,T
def test_merge(p=0.3,trials=10000,n=5):
    bad=[]
    for _ in range(trials):
        bs=[random.random() for _ in range(n)]
        # choose pair with sum<=1
        pairs=[(i,j) for i in range(n) for j in range(i+1,n) if bs[i]+bs[j]<=1]
        if not pairs: continue
        i,j=random.choice(pairs)
        F=hug_F(bs,p)[0]
        bs2=[bs[k] for k in range(n) if k not in (i,j)]+[bs[i]+bs[j]]
        F2=hug_F(bs2,p)[0]
        if F2 < F - 1e-9: # merge decreases F (worse)
            bad.append((F,F2,bs,i,j))
            break
    return bad[:1]
for p in [0.2,0.3,1/3]:
    print(p,test_merge(p,1000,6))

def test_merge_sign(p=0.3,trials=10000,n=5):
    inc=dec=0; ex_inc=None; ex_dec=None
    for _ in range(trials):
        bs=[random.random() for _ in range(n)]
        pairs=[(i,j) for i in range(n) for j in range(i+1,n) if bs[i]+bs[j]<=1]
        if not pairs: continue
        for i,j in pairs[:1]:
            F=hug_F(bs,p)[0]
            bs2=[bs[k] for k in range(n) if k not in (i,j)]+[bs[i]+bs[j]]
            F2=hug_F(bs2,p)[0]
            if F2>F+1e-9:
                inc+=1; ex_inc=(F,F2,bs,i,j); break
            elif F2<F-1e-9:
                dec+=1; ex_dec=(F,F2,bs,i,j); break
    return inc,dec,ex_inc,ex_dec
